import {renderModifierState,modifiers} from '@acepad/keypad';
const {getModifier,setModifier}=modifiers;
export function unsetSel(editor){
    if(unsetSel.t)clearTimeout(unsetSel.t);
    unsetSel.t=setTimeout(function (){
        if(getModifier("select")&&!selMode(editor)){
            setModifier("select",0);
            renderModifierState();
        }
    },100);
}
export function selMode(editor){
    return editor.getSelectedText();
}
export function quitEdit(editor){
    unsetSel(editor);
    editor.getSelection().clearSelection();
    setModifier("edit",0);
    renderModifierState();
}
            

